#include <stdio.h>
int main() {
    int a = 10, b = 5;
    printf("%d\n", a == b);  // 0 (false)
    printf("%d\n", a != b);  // 1 (true)
    printf("%d\n", a > b);   // 1 (true)
    printf("%d\n", a < b);   // 0 (false)
    printf("%d\n", a >= 10); // 1 (true)
    return 0;
}

#include <stdbool.h>  // C99+
bool isReady = true;
bool isDone = false;
printf("%d\n", isReady);  // 1
printf("%d\n", isDone);   // 0

// Without stdbool.h — use int:
int flag = 1;   // true
int done = 0;   // false

int x = 0;
// Safe: x != 0 is false → right side skipped → no crash!
if (x != 0 && (10 / x > 2)) {
    printf("ok\n");
}
// Without short-circuit, 10/0 would crash the program!

int a = 5;
printf("%d\n", ++a); // 6 (increment THEN print)
printf("%d\n", a++); // 6 (print THEN increment)
printf("%d\n", a);   // 7

// In simple statements, both are equivalent:
a++;   // equivalent to: a = a + 1;

