examples.code:
#include <stdio.h>
int main() {
    int score = 75;

    if (score >= 90) {
        printf("A\n");
    } else if (score >= 80) {
        printf("B\n");
    } else if (score >= 70) {
        printf("C\n");
    } else {
        printf("F\n");
    }
    return 0;
}
// Output: C

int lives = 3;
// C allows int in conditions directly:
if (lives) {
    printf("Still alive!\n"); // runs — 3 is non-zero
}

int dead = 0;
if (!dead) {
    printf("Not dead yet!\n"); // runs — !0 = 1 = true
}

int x = 5;
if (x > 0)
    if (x > 10)
        printf("big\n");
    else
        printf("small\n");  // belongs to inner if, NOT outer!

// What you might think (wrong):
// If x > 0: if x > 10 print big
// Else (if x NOT > 0): print small

// What actually happens:
// x=5: outer if true, inner if(5>10) false → else: 'small'
// Fix: use {}

