examples.code:
#include <stdio.h>
int main() {
    int day = 3;
    switch (day) {
        case 1: printf("Mon\n"); break;
        case 2: printf("Tue\n"); break;
        case 3: printf("Wed\n"); break;
        default: printf("Other\n");
    }
    return 0;
}
// Output: Wed

char grade = 'B';
switch (grade) {
    case 'A': printf("Excellent!\n"); break;
    case 'B': printf("Good!\n"); break;
    case 'C': printf("Pass\n"); break;
    default: printf("Fail\n");
}
// Output: Good!

int age = 20;
char *status = (age >= 18) ? "adult" : "minor";
printf("%s\n", status);  // adult

int a = 5, b = 9;
int max = (a > b) ? a : b;
printf("%d\n", max);  // 9

// Ternary in printf directly:
int x = 7;
printf("%s\n", (x % 2 == 0) ? "even" : "odd");  // odd

